import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { getGuardHealthStateDir } from "./guard-health";
import type { GuardHealthSummary } from "./guard-health";

/**
 * Minimum time between two notifications of the SAME critical-escalation
 * signature, within one session. Chosen to match `STALE_ESCALATION_WINDOW_MS`
 * (guard-health.ts) in magnitude — a proven, already-vetted freshness cadence
 * in this same subsystem — while staying an independently tunable constant,
 * since the two concerns (stale-vs-live classification, notification
 * cadence) are conceptually separate. 1h bounds even a fast-moving
 * conversation (many turns in an hour) to at most one repeat notification
 * per hour for an UNCHANGED critical state, while still surfacing again
 * well before the guard-health log's own 24h streak age-out — so the
 * escalation is never silently forgotten for the streak's full lifetime.
 */
export const ESCALATION_NOTIFY_COOLDOWN_MS = 60 * 60 * 1000;

interface NotifyState {
  signature: string;
  lastSurfacedAt: string;
}

export interface EscalationNotifyFsDeps {
  existsSync: (p: string) => boolean;
  mkdirSync: (p: string, opts?: { recursive?: boolean }) => void;
  readFileSync: (p: string, encoding: "utf-8") => string;
  writeFileSync: (p: string, data: string) => void;
}

const REAL_FS: EscalationNotifyFsDeps = { existsSync, mkdirSync, readFileSync, writeFileSync };

function storeDir(env?: NodeJS.ProcessEnv): string {
  return join(getGuardHealthStateDir(env), "guard-health-escalation-notify");
}

/**
 * Composite identity for the CURRENT critical-escalation state: every
 * currently-critical guard's name plus its last failure's timestamp and
 * message, sorted by guard name and joined. Deliberately EXCLUDES
 * `consecutiveStreak` / `failureCount24h` / `failureCount7d` — those drift
 * over time purely from the clock advancing (events aging out of the 24h/7d
 * windows) even with NO new failure, and must not by themselves re-trigger a
 * notification. The signature changes only when a genuinely new event
 * occurs: a new failure extends a streak (fresh timestamp/message) or a
 * guard newly becomes (or stops being) critical.
 */
export function escalationSignature(summary: GuardHealthSummary): string {
  return summary.criticalGuards
    .slice()
    .sort()
    .map((name) => {
      const lastEvent = summary.byGuard[name]?.lastEvent;
      return `${name}:${lastEvent?.timestamp ?? ""}:${lastEvent?.message ?? ""}`;
    })
    .join("|");
}

export interface EscalationNotifyOptions {
  fs?: EscalationNotifyFsDeps;
  env?: NodeJS.ProcessEnv;
  now?: () => Date;
  cooldownMs?: number;
  /** Test seam — override the resolved store directory directly. */
  dir?: string;
}

/**
 * Decide whether `signature` should surface a notification to `sessionId`
 * right now, and persist that decision for next time. Pure decision, real
 * (best-effort) I/O — mirrors `guard-health.ts`'s own fail-open posture:
 *
 * - No prior record for this session -> surface (first time this
 *   conversation has seen ANY critical escalation).
 * - Prior record with a DIFFERENT signature -> surface (something changed:
 *   a new failure, or a different set of critical guards).
 * - Prior record with the SAME signature, cooldown elapsed -> surface (the
 *   periodic reminder that keeps this from being silently forgotten).
 * - Prior record with the SAME signature, still within cooldown -> suppress.
 *
 * Fail-open on any store read/write error: an unreadable or unwritable store
 * must never SILENTLY suppress a critical warning — that would recreate
 * exactly the opacity this task exists to remove. A write failure only means
 * the NEXT call also surfaces (never blocks the surface decision already made
 * this call).
 */
export function shouldNotifyEscalation(
  sessionId: string,
  signature: string,
  options?: EscalationNotifyOptions
): boolean {
  const fs = options?.fs ?? REAL_FS;
  const now = (options?.now ?? (() => new Date()))();
  const cooldownMs = options?.cooldownMs ?? ESCALATION_NOTIFY_COOLDOWN_MS;
  const dir = options?.dir ?? storeDir(options?.env);
  const safe = (sessionId || "unknown-session").replace(/[^A-Za-z0-9_-]/g, "_");
  const path = join(dir, `${safe}.json`);

  let prior: NotifyState | null = null;
  try {
    if (fs.existsSync(path)) {
      const parsed = JSON.parse(fs.readFileSync(path, "utf-8")) as Partial<NotifyState>;
      if (typeof parsed.signature === "string" && typeof parsed.lastSurfacedAt === "string") {
        prior = { signature: parsed.signature, lastSurfacedAt: parsed.lastSurfacedAt };
      }
    }
  } catch {
    prior = null; // fail-open: unreadable store reads as "never surfaced"
  }

  const withinCooldown =
    prior !== null &&
    prior.signature === signature &&
    now.getTime() - new Date(prior.lastSurfacedAt).getTime() < cooldownMs;

  if (withinCooldown) return false;

  try {
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    const next: NotifyState = { signature, lastSurfacedAt: now.toISOString() };
    fs.writeFileSync(path, JSON.stringify(next));
  } catch {
    // Best-effort — a failed write just means the NEXT call also surfaces;
    // never suppress the (already-decided) surface this call.
  }
  return true;
}
